var flakes = state.flakes;
if (!flakes) return state;
var w = dimensionContext.width;
var h = dimensionContext.height;
for (var i = 0; i < flakes.length; i++) {
  var f = flakes[i];
  var wind = Math.sin(framesElapsed * 0.01 + f.phase + f.y * 0.01) * 0.35;
  f.x += f.vx + wind;
  f.y += f.vy;
  f.phase += f.spin;
  if (f.y > h + 8) {
    f.y = -8;
    f.x = R.dec() * w;
  }
  if (f.x < -12) f.x = w + 12;
  if (f.x > w + 12) f.x = -12;
}
return state;
